scwin.btn_zip_onclick = async function (e) {
  var opts = {
    id: "smpPop",
    popupName: "우편번호 검색",
    modal: true,
    type: "browserPopup" //화면 오픈 타입 ("pageFramePopup", "browserPopup")
    ,

    title: "우편번호 검색",
    width: 600,
    height: 450
  };
  var popupResult = await $c.win.openPopup($p, "/ui/cm/zz/newzipcodePopup.xml", opts);

  // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
  if (popupResult != null) {
    ed_zip.setValue(popupResult.zip);
    ed_addr1.setValue(popupResult.addr1);
  }
};
scwin.f_chkField = function (chgValue1, chgValue2, disGubun) {
  var chgObj1 = eval(chgValue1);
  var chgObj2 = eval(chgValue2);
  var objType1 = chgValue1.substr(0, 2);
  var objType2 = chgValue2.substr(0, 2);
  if (objType1 == "ed") {
    if (chgObj1.getValue().trim() == "") {
      chgObj2.setValue("");
    } else {
      chgObj2.setValue("");
      scwin.f_openPopUp(disGubun, "T");
    }
  } else {
    if (chgObj1.getValue().trim() == "") {
      if (objType2 == "ed") {
        chgObj2.setValue("");
      } else {
        chgObj2.setValue("");
      }
    } else {
      if (objType2 == "ed") {
        chgObj2.setValue("");
      } else {
        chgObj2.setValue("");
      }
      scwin.f_openPopUp(disGubun, "T");
    }
  }
};

