// <!-- 데이타셋 로우 변경전 이벤트 -->
// for=ds_wrkpl event=CanRowPosChange(row)
scwin.ds_wrkpl_onbeforerowpositionchange = async function (info) {
  var row = info.oldRowIndex;
  var newRow = info.newRowIndex;
  if (scwin.chkSkip) {
    scwin.chkSkip = false;
    return false;
  }

  // if (row != null && newRow != null) {
  if (ds_wrkpl.getModifiedIndex().length != 0) {
    //필수입력항목 체크
    scwin.rowChange = false;
    if (row != null) {
      if (!(await scwin.f_ReqFieldChk(row))) {
        ds_wrkpl.setEventPause("", true);
        gr_wrkpl.setFocusedCell(row, 0);
        ds_wrkpl.setEventPause("", false);
        return false;
      }
    }
    scwin.rowChange = true;

    //return cfValidate([gr_district])
    let validArray = [{
      id: "districtCd",
      name: "지역코드",
      mandatory: true
    }];
    var ret = await $c.gus.cfValidateGrid($p, gr_district, null, null, validArray, "소속지역");
    // return ret;
    if (ret) {
      scwin.ds_wrkpl_onrowpositionchange(info);
    }
  }
};

// <!-- 데이타셋 로우 변경후 이벤트 -->
// for=ds_wrkpl event=OnRowPosChanged(row)
// scwin.gr_wrkpl_onrowindexchange = function (rowIndex, oldRow) {
scwin.ds_wrkpl_onrowpositionchange = function (info) {
  var rowIndex = info.newRowIndex;
  if (!scwin.rowChange) {
    scwin.rowChange = true;
    return;
  }
  if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
    lc_wrkPlClsCd.setDisabled(false);
  } else {
    lc_wrkPlClsCd.setDisabled(true);
  }
  if (rowIndex > -1 && rowIndex != null) {
    $c.gus.cfPrepareObjectHidVal($p, ds_wrkpl, rowIndex, ["lobranCd", "lobranNm", "upperWrkPlCd", "upperWrkPlNm", "portCd", "portNm", "pierYardWrkPlCd", "pierYardWrkPlNm", "pierOpClntNo", "pierOpClntNm"], [txt_lobranCd, txt_lobranNm, ed_upperWrkPlCd, txt_upperWrkPlNm, txt_portCd, txt_portNm, txt_pierYardWrkPlCd, txt_pierYardWrkPlNm, ed_pierOpClntNo, txt_pierOpClntNm]);
    $c.gus.cfEnableObjects($p, [oRecevInfo]);
    if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    } else {
      $c.gus.cfDisableKey($p);
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    }
    if (ds_wrkpl.getCellData(rowIndex, "pierPosnClsCd") == "TP" || ds_wrkpl.getCellData(rowIndex, "pierPosnClsCd") == "JT") {
      $c.gus.cfEnableObjects($p, [ed_pierOpClntNo, txt_pierOpClntNm, btn_pierOpClntNo]);
    } else {
      $c.gus.cfDisableObjects($p, [ed_pierOpClntNo, txt_pierOpClntNm, btn_pierOpClntNo]);
      ed_pierOpClntNo.setValue("");
      txt_pierOpClntNm.setValue("");
    }
    if (ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd") == "B") {
      tbx_upperWrkPlCd.addClass("req");
      //document.all.divupperWrkPlCd.style.display="";
    } else {
      tbx_upperWrkPlCd.removeClass("req");
      //document.all.divupperWrkPlCd.style.display="none";
    }
  }

  //콤보박스 값 세팅
  //lc_wrkPlClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd"));
  //acb_WrkPlPosnClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd"));
  //acb_OwnerCd.setValue(ds_wrkpl.getCellData(rowIndex, "ownerCd"));

  scwin.f_districtFilter();
  totalRows2.setValue(ds_district.getRowCount());
  $c.gus.cfEnableBtnOnly($p, [btn_save, btn_adddistrict, btn_deldistrict, btn_clsdistrict]);
  //cfShowTotalRows(totalRows2, ds_district.getRowCount());
};
