// <!-- Grid PopUp : Popup 버튼 클릭시 -->
// <script language=JavaScript for=gr_district event=OnPopup(row,colid,data)>
scwin.gr_district_ontextimageclick = function (rowIndex, columnIndex) {
  var colid = gr_district.getFocusedColumnID();
  if (scwin.popupOpen) {
    // gr_district_onafteredit 이벤트랑 중복발생방지
    return;
  }
  switch (colid) {
    //권역
    case "districtCd":
      scwin.f_openCommPopUpGrid(1, rowIndex, 'F');
      break;
    case "districtNm":
      scwin.f_openCommPopUpGrid(2, rowIndex, 'F');
      break;
  }
};
scwin.gr_district_onbeforeedit = function (rowIndex, columnIndex, value) {
  scwin.olddata = value;
};

// <!-- Grid PopUp : 코드 입력후 Focus 이동시 -->
// <script language="javascript" for=gr_district event=OnExit(Row,Colid,olddata)>
scwin.gr_district_onafteredit = function (row, columnIndex, value) {
  var Colid = gr_district.getFocusedColumnID();
  switch (Colid) {
    case "districtCd":
      if (value != "" && value != scwin.olddata) {
        ds_district.setCellData(row, "districtNm", "");
        ds_district.setCellData(row, "districtCd", value);
        scwin.popupOpen = true;
        scwin.f_openCommPopUpGrid(1, row, 'T');
      } else if (value == "") {
        ds_district.setCellData(row, "districtCd", "");
        ds_district.setCellData(row, "districtNm", "");
      }
      break;
    case "districtNm":
      if (value != "" && value != scwin.olddata) {
        ds_district.setCellData(row, "districtCd", "");
        ds_district.setCellData(row, "districtNm", value);
        scwin.popupOpen = true;
        scwin.f_openCommPopUpGrid(2, row, 'T');
      } else if (value == "") {
        ds_district.setCellData(row, "districtCd", "");
        ds_district.setCellData(row, "districtNm", "");
      }
      break;
  }
};

